#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int value;
    int weight;
    double ratio;
} Item;

int cmp(const void *a, const void *b) {
    const Item *i1 = (const Item *)a;
    const Item *i2 = (const Item *)b;
    if (i1->ratio < i2->ratio) return 1;
    if (i1->ratio > i2->ratio) return -1;
    return 0;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; long long C; scanf("%d %lld", &N, &C);
        Item *items = (Item *)malloc(N * sizeof(Item));
        for (int i = 0; i < N; ++i) scanf("%d", &items[i].value);
        for (int i = 0; i < N; ++i) {
            scanf("%d", &items[i].weight);
            items[i].ratio = (double)items[i].value / items[i].weight;
        }
        qsort(items, N, sizeof(Item), cmp);
        double total = 0.0;
        long long used = 0;
        for (int i = 0; i < N; ++i) {
            if (used + items[i].weight <= C) {
                used += items[i].weight;
                total += items[i].value;
            } else {
                long long remain = C - used;
                if (remain > 0) total += items[i].value * ((double)remain / items[i].weight);
                break;
            }
        }
        printf("%.6f\n", total);
        free(items);
    }
    return 0;
}

