import java.io.*;
import java.util.*;

public class Main {
    static class Item {
        int value;
        int weight;
        double ratio;
        Item(int v, int w){value=v; weight=w; ratio=(double)v/w;}
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        while(T-- > 0){
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            long C = Long.parseLong(st.nextToken());
            int[] vals = new int[N];
            int[] wts = new int[N];
            st = new StringTokenizer(br.readLine());
            for(int i=0;i<N;i++) vals[i]=Integer.parseInt(st.nextToken());
            st = new StringTokenizer(br.readLine());
            for(int i=0;i<N;i++) wts[i]=Integer.parseInt(st.nextToken());
            Item[] items = new Item[N];
            for(int i=0;i<N;i++) items[i]=new Item(vals[i], wts[i]);
            Arrays.sort(items, (a,b)->Double.compare(b.ratio, a.ratio));
            double total=0.0;
            long used=0;
            for(Item it: items){
                if(used + it.weight <= C){
                    used += it.weight;
                    total += it.value;
                } else {
                    long remain = C - used;
                    if(remain>0) total += it.value * ((double)remain / it.weight);
                    break;
                }
            }
            sb.append(String.format(java.util.Locale.US, "%.6f\n", total));
        }
        System.out.print(sb.toString());
    }
}

