let outputs = [];
for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  const C = Number(input[idx++]);
  const values = new Array(N);
  const weights = new Array(N);
  for (let i = 0; i < N; ++i) values[i] = Number(input[idx++]);
  for (let i = 0; i < N; ++i) weights[i] = Number(input[idx++]);
  const items = [];
  for (let i = 0; i < N; ++i) {
    items.push({ ratio: values[i] / weights[i], value: values[i], weight: weights[i] });
  }
  items.sort((a, b) => b.ratio - a.ratio);
  let total = 0.0;
  let used = 0;
  for (const it of items) {
    if (used + it.weight <= C) {
      used += it.weight;
      total += it.value;
